          } ${isHovered || isWished(product.name) ? "opacity-100" : "opacity-0"}`}
          aria-label={isWished(product.name) ? (s.removeFav || "Quitar de favoritos") : (s.addFav || "Agregar a favoritos")}
        >
          <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="[REDACTED_PHONE]" fill={isWished(product.name) ? "currentColor" : "none"} stroke="currentColor" strokeWidth="2">
            <path d="M19 14c1.49-1.46 3-3.21 3-5.5A5.5 5.[REDACTED_PHONE].5 3c-1.76 0-3 .5-4.5 2-1.5-1.5-2.74-2-4.5-2A5.5 5.[REDACTED_PHONE].5c0 2.3 1.5 4.05 3 5.5l7 7Z"/>
          </svg>
        </button>
