                      }`}>
                        {checked && <svg xmlns="http://www.w3.org/2000/svg" width="10" height="10" viewBox="[REDACTED_PHONE]" fill="none" stroke="white" strokeWidth="3"><path d="M[REDACTED_PHONE]l-5-5"/></svg>}
                      </div>
                      <input type="checkbox" className="sr-only" checked={checked} onChange={() => section.onToggle(opt.value)} />
                      <span className="flex-1 text-sm text-foreground">{opt.label}</span>
                      {opt.count !== undefined && <span className="text-xs text-muted-foreground">({opt.count})</span>}
                    </label>
                  )
                })}
