// Sync filter state to query params for shareability and persistence.
// Use replaceState (not pushState) to avoid polluting browser history.

import { useSearchParams, usePathname } from "next/navigation"
import { useState, useEffect, useCallback, useMemo } from "react"

// Example: read array param like ?cat=Camping,Pesca
function readArrParam(searchParams: URLSearchParams, key: string): string[] {
  const v = searchParams.get(key)
  return v ? v.split(",") : []
}

function readNumParam(searchParams: URLSearchParams, key: string, def: number): number {
  const v = searchParams.get(key)
  return v ? Number(v) || def : def
}

// Example usage in a component:
export function useCatalogFilters() {
  const searchParams = useSearchParams()
  const pathname = usePathname()

  const [search, setSearch] = useState(searchParams.get("q") || "")
  const [selectedCats, setSelectedCats] = useState<string[]>(() => readArrParam(searchParams, "cat"))
  const [selectedBrands, setSelectedBrands] = useState<string[]>(() => readArrParam(searchParams, "brand"))
  const [sortBy, setSortBy] = useState(searchParams.get("sort") || "")
  const [priceMin, setPriceMin] = useState(readNumParam(searchParams, "pmin", 0))
  const [priceMax, setPriceMax] = useState(readNumParam(searchParams, "pmax", 0))
  const [page, setPage] = useState(readNumParam(searchParams, "page", 1))

  // Build query string from current state
  const buildQuery = useCallback(() => {
    const params = new URLSearchParams()
    if (search) params.set("q", search)
    if (selectedCats.length) params.set("cat", selectedCats.join(","))
    if (selectedBrands.length) params.set("brand", selectedBrands.join(","))
    if (sortBy) params.set("sort", sortBy)
    if (priceMin > 0) params.set("pmin", String(priceMin))
    if (priceMax > 0) params.set("pmax", String(priceMax))
    if (page > 1) params.set("page", String(page))
    return params.toString()
  }, [search, selectedCats, selectedBrands, sortBy, priceMin, priceMax, page])

  // Sync to URL (replaceState, not pushState)
  useEffect(() => {
    const qs = buildQuery()
    const url = qs ? `${pathname}?${qs}` : pathname
    window.history.replaceState(null, "", url)
  }, [buildQuery, pathname])

  // Reset page to 1 when filters change
  const setSearchAndReset = (val: string) => { setSearch(val); setPage(1) }
  const toggleCat = (cat: string) => {
    setSelectedCats(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])
    setPage(1)
  }

  return {
    search, selectedCats, selectedBrands, sortBy, priceMin, priceMax, page,
    setSearch: setSearchAndReset, toggleCat, setPage,
    buildQuery,
  }
}

// Important: wrap your page in <Suspense> when using useSearchParams
// because it reads from the browser URL during hydration.
